class Solution(object):
    def lastRemaining(self, n):
        left = 1
        remaining = n
        step = 1
        left_to_right = True
        while remaining > 1:
            if left_to_right or remaining % 2 == 1:
                left += step
            remaining //= 2
            step *= 2
            left_to_right = not left_to_right
        return left
